{
  "mode": "io",
  "tests": [
    {
      "name": "logged_out_user_navigation",
      "input": "GET /projects",
      "output": "User is not shown as logged out in the uni nav",
      "notes": "Validates that a logged-out user does not see a logged-out indication in the navigation."
    },
    {
      "name": "logged_in_user_navigation",
      "input": "GET /projects?user=logged_in",
      "output": "User is shown as logged in in the uni nav",
      "notes": "Ensures that a logged-in user sees the correct navigation state."
    },
    {
      "name": "session_timeout",
      "input": "GET /projects?session=expired",
      "output": "User is not shown as logged out in the uni nav",
      "notes": "Tests behavior when a session expires but the user remains on the page."
    },
    {
      "name": "multiple_user_sessions",
      "input": "GET /projects?user=logged_in&session=active",
      "output": "User is shown as logged in in the uni nav",
      "notes": "Checks that multiple active sessions do not affect the navigation state."
    },
    {
      "name": "refresh_page_logged_out",
      "input": "GET /projects?user=logged_out",
      "output": "User is not shown as logged out in the uni nav",
      "notes": "Validates that refreshing the page does not change the logged-out indication."
    },
    {
      "name": "navigate_after_logout",
      "input": "GET /projects?user=logged_out&action=navigate",
      "output": "User is not shown as logged out in the uni nav",
      "notes": "Tests navigation after logging out to ensure the state remains consistent."
    },
    {
      "name": "direct_access_logged_out",
      "input": "GET /projects?user=logged_out&direct_access=true",
      "output": "User is not shown as logged out in the uni nav",
      "notes": "Checks if direct access to the projects page maintains the logged-out state."
    },
    {
      "name": "logged_out_user_with_cache",
      "input": "GET /projects?user=logged_out&cache=true",
      "output": "User is not shown as logged out in the uni nav",
      "notes": "Validates that cached pages do not incorrectly show logged-out status."
    }
  ],
  "assumptions": "User states (logged in/out) are correctly managed by the session.",
  "notes": "Ensure to test various user states and navigation scenarios."
}
